// map a (dx, dy) from center to {reason: index | null, intensity: 0..1}
// returns reason=null when inside the dead zone (cancel).
function pointToBid(dx: number, dy: number): { reasonIdx: number | null; intensity: number } {
  const dist = Math.sqrt(dx * dx + dy * dy);
  if (dist < INNER) return { reasonIdx: null, intensity: 0 };
  const intensity = Math.min(1, (dist - INNER) / (RADIUS - INNER));
  // angle from top, clockwise, in [0, 360)
  let ang = (Math.atan2(dy, dx) * 180) / Math.PI + 90;
  if (ang < 0) ang += 360;
  const wedgeArc = 360 / WEDGES.length;
  const idx = Math.floor(((ang + wedgeArc / 2) % 360) / wedgeArc);
  return { reasonIdx: idx % WEDGES.length, intensity };
}

