.bid-row { grid-template-columns: 1fr 28px 180px 40px; }

/* Floating BID FAB — fixed bottom-right. Doesn't move when roles change. */
.bid-fab {
  position: fixed;
  right: 24px;
  bottom: 24px;
  z-index: 50;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  padding: 14px 22px;
  background: var(--accent);
  color: #001220;
  border: none;
  border-radius: 14px;
  font-weight: 800;
  letter-spacing: 0.06em;
  cursor: pointer;
  box-shadow: 0 8px 28px rgba(124, 211, 255, 0.35), 0 0 0 1px rgba(124, 211, 255, 0.4);
  transition: transform 80ms, filter 120ms, box-shadow 180ms;
}
.bid-fab:hover {
  filter: brightness(1.08);
  transform: translateY(-1px);
  box-shadow: 0 10px 34px rgba(124, 211, 255, 0.45), 0 0 0 1px rgba(124, 211, 255, 0.5);
}
.bid-fab:active { transform: translateY(0); }

/* Dev panel — solo-test levers, only shown when ?dev=1 or
   localStorage.antiphon-dev=1 is set. Not part of the product UX. */
.dev-panel {
  position: fixed;
  bottom: 24px;
  left: 24px;
  z-index: 50;
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 12px 14px;
  background: var(--panel-2);
  border: 1px solid #2a323f;
  border-radius: 10px;
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.4);
  font-family: var(--font-mono);
  font-size: 12px;
  min-width: 220px;
}
.dev-panel-tag {
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 0.18em;
  color: #ff8aff;
  margin-bottom: 2px;
}
.dev-row { display: flex; align-items: center; gap: 8px; }
.dev-row label { color: var(--ink-dim); width: 60px; }
.dev-row select, .dev-row input {
  flex: 1;
  background: var(--panel);
  color: var(--ink);
  border: 1px solid #2a323f;
  border-radius: 4px;
  padding: 3px 6px;
  font-family: inherit;
  font-size: 11px;
}
.dev-panel button {
  background: var(--panel);
  color: var(--ink);
  border: 1px solid #2a323f;
  border-radius: 4px;
  padding: 4px 8px;
  cursor: pointer;
  font-family: inherit;
  font-size: 11px;
  text-align: left;
}
.dev-panel button:hover { border-color: var(--accent); color: var(--accent); }
.dev-panel button.dev-reset { color: var(--reason-disagree); border-color: rgba(255, 108, 108, 0.4); }
.dev-panel button.dev-reset:hover { background: rgba(255, 108, 108, 0.1); }
.bid-fab-label { font-size: 16px; font-weight: 800; }
.bid-fab-kbd {
  font-size: 9px; font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: rgba(0, 18, 32, 0.65);
  font-family: var(--font-mono);
}

