const [activeIntervention, setActiveIntervention] = useState<Intervention | null>(null);
// Persona driver — flavor C in docs/roadmap/simulation-harness.md.
// Ticks every 4 seconds; picks next participant in rotation; LLM-calls
// their next action; applies. Only runs when key is configured and the
// driver toggle is on.
const [personaDriverOn, setPersonaDriverOn] = useState(false);
const [personaStatus, setPersonaStatus] = useState<string>("");
const [utterances, setUtterances] = useState<Record<string, string>>({});
const personaIdxRef = useRef(0);
const driverEventLogRef = useRef<string[]>([]);
const driverLastTickRef = useRef(Date.now());
const apiKey = (import.meta as { env?: Record<string, string> }).env?.VITE_ANTHROPIC_API_KEY ?? "";
const apiModel = (import.meta as { env?: Record<string, string> }).env?.VITE_ANTHROPIC_MODEL ?? "claude-sonnet-4-6";
const apiTemp = parseFloat((import.meta as { env?: Record<string, string> }).env?.VITE_ANTHROPIC_TEMPERATURE ?? "0.6");

function logDriverEvent(line: string) {
  const tSec = ((Date.now() - driverLastTickRef.current) / 1000).toFixed(1);
  driverEventLogRef.current = [...driverEventLogRef.current, `T+${tSec}s: ${line}`].slice(-30);
}

useEffect(() => {
  if (!personaDriverOn) return;
  if (!apiKey) {
    setPersonaStatus("error: VITE_ANTHROPIC_API_KEY not set");
    setPersonaDriverOn(false);
    return;
  }
  let cancelled = false;
  driverLastTickRef.current = Date.now();
  setPersonaStatus("running");
  async function tick() {
    if (cancelled || !personaDriverOn) return;
    const target = participants[personaIdxRef.current % participants.length];
    personaIdxRef.current = (personaIdxRef.current + 1) % participants.length;
    if (!target?.persona) {
      setPersonaStatus(`${target?.name ?? "?"} has no persona — skipping`);
      return;
    }
    setPersonaStatus(`thinking: ${target.name}…`);
    const opts: PersonaDriverOpts = { apiKey, model: apiModel, temperature: apiTemp };
    const ctx: PersonaContext = {
      participant: { name: target.name, station: target.station, persona: target.persona, pronouns: target.pronouns },
      role: target.role,
      currentBid: target.bid,
      currentReason: target.reason,
      missionObjective: currentMission.objective,
      decisionsOpen: decisions.filter((d) => d.status === "open").map((d) => d.title),
      recentEvents: driverEventLogRef.current,
    };
    const action = await generatePersonaAction(ctx, opts);
    if (cancelled) return;

    switch (action.kind) {
      case "speak":
        setUtterances((prev) => ({ ...prev, [target.id]: action.speak }));
        // Clear the utterance after 8s.
        window.setTimeout(() => {
          setUtterances((prev) => {
            if (prev[target.id] !== action.speak) return prev;
            const next = { ...prev };
            delete next[target.id];
            return next;
          });
        }, 8000);
        logDriverEvent(`${target.name} (${target.station}) says: "${action.speak.slice(0, 80)}"`);
        break;
      case "bid":
        if (action.bid) {
          setParticipants((prev) =>
            prev.map((p) =>
              p.id === target.id
                ? { ...p, bid: action.bid!.intensity, reason: action.bid!.reason, lastEngagementMs: Date.now() }
                : p,
            ),
          );
          logDriverEvent(`${target.name} (${target.station}) bid ${Math.round(action.bid.intensity * 100)} ${action.bid.reason} — ${action.rationale.slice(0, 60)}`);
        }
        break;
      case "vibe":
        if (action.vibe && currentSpeakerId) {
