// LLM persona driver — flavor C in docs/roadmap/simulation-harness.md.
// Each tick, generate one persona's next action via a single Claude API
// call. Returns a structured action the spike applies to state.
//
// IMPORTANT: this calls the Anthropic API directly from the browser
// (anthropic-dangerous-direct-browser-access). Solo spike testing only;
// production must proxy through a backend that holds the key server-side.

import type { Persona, Reason, VibeKind } from "./types";

export type PersonaAction =
  | { kind: "speak"; speak: string; rationale: string }
  | { kind: "bid"; bid: { intensity: number; reason: Reason }; rationale: string }
  | { kind: "vibe"; vibe: VibeKind; rationale: string }
  | { kind: "pass"; rationale: string };

export interface PersonaContext {
  participant: { name: string; station: string; persona: Persona; pronouns?: string };
  role: "speaker" | "on-deck" | "idle";
  currentBid: number;
  currentReason: Reason;
  missionObjective: string;
  decisionsOpen: string[];
  // Newest last; each line is "T+12s: Sara (finance) speaker bid 0.6 build-on" etc.
  recentEvents: string[];
  // Live floor-state — lets personas react to overrunning speakers etc.
  currentSpeaker?: { name: string; station: string; secondsHeld: number };
  turnCapSeconds: number;
}

export interface PersonaDriverOpts {
  apiKey: string;
  model: string;
  temperature: number;
}

// Static prompt (system) — cacheable. Only mission + persona + recent events
// vary per call, and those live in the user message.
const SYSTEM_PROMPT = `You simulate a meeting participant in a multi-party real-time decision-making session called Antiphon.

Each call: produce ONE next action. Return JSON only, no markdown fences, no other text.

Available actions:

1. {"kind": "speak", "speak": "<1-2 short sentences of what you say>", "rationale": "..."}
   - Only valid when YOUR ROLE is "speaker". Continues your turn.
   - Stay tight. Say something specific to the mission and your station.
   - Do NOT name your own station / persona meta-text. Just speak naturally.
   - If you've been speaker a while, push toward landing something, not restating.

2. {"kind": "bid", "bid": {"intensity": <0..1>, "reason": "<question|disagree|build-on|time-check|repair>"}, "rationale": "..."}
   - Push for the floor (intensity > 0.5) or back off (intensity < 0.3) or stay (close to current).
   - Reason tags: question = ask a clarifying question; disagree = push back; build-on = extend what was said; time-check = call for closure; repair = fix a misunderstanding.
   - Pick the reason that best matches what you'd say if given the floor.

3. {"kind": "vibe", "vibe": "<Y|N|W|I|S>", "rationale": "..."}
   - Quick non-floor reaction. Y=agree, N=disagree, W=lost/what?, I=interesting, S=stuck.
   - Use when you want to signal sentiment without taking the floor.

4. {"kind": "pass", "rationale": "..."}
   - Genuinely nothing to do this beat. Use sparingly — meetings have momentum.

CRITICAL FLOOR RULES (these override your default temperament):

- If the CURRENT SPEAKER is past their turn cap and is NOT you: bid HARD (intensity 0.80+) with reason="time-check" or "repair" to take the floor. Real meetings don't let one person monopolize past cap — someone has to interrupt. Pick "time-check" if you want closure, "repair" if there's a misunderstanding, "disagree" if you genuinely disagree.

- If you are an active station whose specialty is on the table and the speaker hasn't addressed it: bid 0.6-0.8 with "build-on" or "question" — don't sit silent while your area is being decided around you.

- If you've been silent for many beats AND your station is relevant: bid up. Don't perform-passivity — your job here is to surface your specialty's read.

- Use "pass" only when you genuinely have no new signal AND the room is in good shape. If the room is stuck or someone is overrunning, a "pass" is wrong.

Stay in character but obey the floor rules. Concise. JSON only.`;

function buildUserMessage(ctx: PersonaContext): string {
  const speakerInfo = ctx.currentSpeaker
    ? (() => {
        const overBy = ctx.currentSpeaker.secondsHeld - ctx.turnCapSeconds;
        const overrunNote = overBy > 0
          ? `  ⚠️ PAST CAP by ${Math.round(overBy)}s — the speaker is monopolizing. If you are not them, time to push for the floor.`
          : "";
        return [
          `FLOOR: ${ctx.currentSpeaker.name} (${ctx.currentSpeaker.station}) has held the floor for ${Math.round(ctx.currentSpeaker.secondsHeld)}s / cap ${ctx.turnCapSeconds}s.`,
          overrunNote,
        ].filter(Boolean).join("\n");
      })()
    : `FLOOR: nobody is speaking. Turn cap ${ctx.turnCapSeconds}s.`;

  return [
    `MISSION: ${ctx.missionObjective}`,
    "",
    "OPEN DECISIONS:",
    ...ctx.decisionsOpen.map((d) => `- ${d}`),
    "",
    speakerInfo,
    "",
    `YOU ARE: ${ctx.participant.name} (${ctx.participant.station} station${ctx.participant.pronouns ? `, ${ctx.participant.pronouns}` : ""})`,
    `BACKGROUND: ${ctx.participant.persona.background}`,
    `TENDENCIES: ${ctx.participant.persona.tendencies}`,
    `CURRENT ROLE: ${ctx.role}`,
    `CURRENT BID: ${Math.round(ctx.currentBid * 100)}% (reason: ${ctx.currentReason})`,
    "",
    "RECENT EVENTS (newest last):",
    ...ctx.recentEvents.slice(-12),
    "",
    "What do you do next? Return JSON only.",
  ].join("\n");
}

export async function generatePersonaAction(
  ctx: PersonaContext,
  opts: PersonaDriverOpts,
): Promise<PersonaAction> {
  const userMessage = buildUserMessage(ctx);
  try {
    const resp = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "x-api-key": opts.apiKey,
        "anthropic-version": "2023-06-01",
        "content-type": "application/json",
        // Required to call from the browser. Solo-spike only.
        "anthropic-dangerous-direct-browser-access": "true",
      },
      body: JSON.stringify({
        model: opts.model,
        max_tokens: 280,
        temperature: opts.temperature,
        system: [
          // cache_control on the static system prompt — repeated across ticks
          { type: "text", text: SYSTEM_PROMPT, cache_control: { type: "ephemeral" } },
        ],
        messages: [{ role: "user", content: userMessage }],
      }),
    });
    if (!resp.ok) {
      const txt = await resp.text();
      throw new Error(`HTTP ${resp.status}: ${txt.slice(0, 200)}`);
    }
    const data = await resp.json() as { content?: Array<{ text?: string }> };
    const text = data.content?.[0]?.text?.trim() ?? "";
    if (!text) return { kind: "pass", rationale: "empty response" };
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return { kind: "pass", rationale: `unparseable: ${text.slice(0, 80)}` };
    const parsed = JSON.parse(jsonMatch[0]) as PersonaAction;
    // Sanity-clamp on bid intensity.
    if (parsed.kind === "bid" && parsed.bid) {
      parsed.bid.intensity = Math.max(0, Math.min(1, parsed.bid.intensity));
    }
    return parsed;
  } catch (err) {
    console.error("[persona]", err);
    return { kind: "pass", rationale: String(err).slice(0, 120) };
  }
}

