// activity, fires proposeIntervention when a pattern is detected.
// Slow tick (12s) + 45s cooldown after a fire so we don't double-fire.
// Same refs-for-live-state pattern as the persona driver (see deps note above).
const detectorStartRef = useRef<number>(Date.now());
const detectorCooldownUntilRef = useRef<number>(0);
useEffect(() => {
  if (!personaDriverOn || !apiKey) return;
  let cancelled = false;
  detectorStartRef.current = Date.now();
  async function tick() {
    if (cancelled || !personaDriverOn) return;
    if (Date.now() < detectorCooldownUntilRef.current) return;
    const events = driverEventLogRef.current;
    // Need enough history for the detector to have a real signal.
    if (events.length < 6) return;
    const openDecisions = decisionsRef.current.filter((d) => d.status === "open");
    const closedCount = decisionsRef.current.length - openDecisions.length;
    const result = await detectIntervention(
      {
        missionObjective: missionObjectiveRef.current,
        decisionsOpen: openDecisions.map((d) => d.title),
        decisionsClosedCount: closedCount,
        recentEvents: events,
        meetingSeconds: (Date.now() - detectorStartRef.current) / 1000,
      },
      { apiKey, model: apiModel, temperature: apiTemp },
    );
    if (cancelled) return;
    if (result.detected && result.kind) {
      proposeIntervention(result.kind, result.evidence);
      // 45s suppression — the surface lasts 25s + a few seconds breathing room.
      detectorCooldownUntilRef.current = Date.now() + 45_000;
    }
  }
  const id = window.setInterval(() => { void tick(); }, 12_000);
  return () => { cancelled = true; window.clearInterval(id); };
}, [personaDriverOn, apiKey, apiModel, apiTemp]);

// Scenario runner — flavor-A scripted simulation (see scenarios.ts).
const [scenarioId, setScenarioId] = useState<string | null>(null);

